+export function calcPartitionsProgress(
+    minPartitions: number,
+    maxPartitions: number | undefined,
+    partitionsCount: number,
+): PartitionsProgressCalcResult {
+    const min = minPartitions;
+
+    const hasMaxLimit = !isNil(maxPartitions);
+
+    if (!hasMaxLimit) {
