+                    <Flex justifyContent="space-between">
+                        <Text variant="body-2" color="secondary">
+                            {min}
+                        </Text>
+                        <Text variant="body-2" color="secondary">
+                            {maxLabel}
+                        </Text>
+                    </Flex>
+                </Flex>
